//! Exhaustive sweep parity: 263 test vectors generated by the real Solidity
//! contracts, covering every method × many input combinations (1 wei → 1M ETH).
//!
//! Fixture: `tests/fixtures/onchain_sweep.json`
//! Generated by: `contracts/core/tests/unit/curves/GenerateSweepFixtures.t.sol`
//!
//! Regenerate:
//!   cd contracts/core && FOUNDRY_PROFILE=test forge test --mt test_generateSweep -vv

use std::{collections::HashMap, fs, path::PathBuf, str::FromStr};

use curves::{Curve, CurveState, LinearCurve, OffsetProgressiveCurve, U256};

type Section = HashMap<String, serde_json::Value>;
type Obj = serde_json::Map<String, serde_json::Value>;

fn load_sweep() -> HashMap<String, Section> {
    let path = PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("tests/fixtures/onchain_sweep.json");
    serde_json::from_str(&fs::read_to_string(path).expect("sweep fixture should exist"))
        .expect("sweep json should deserialize")
}

fn p(v: &serde_json::Value) -> U256 {
    U256::from_str(v.as_str().expect("expected string")).expect("expected U256")
}

fn count(section: &Section) -> usize {
    section["count"].as_str().unwrap().parse::<usize>().unwrap()
}

fn entry<'a>(section: &'a Section, prefix: &str, idx: usize) -> &'a Obj {
    let key = format!("{}_{}", prefix, idx);
    section[&key].as_object().unwrap()
}

// =====================================================================
// Linear curve sweeps
// =====================================================================

#[test]
fn linear_deposit_sweep() {
    let all = load_sweep();
    let sec = &all["linear_deposit"];
    let n = count(sec);
    let curve = LinearCurve::new();
    let mut checked = 0;

    for i in 0..n {
        let e = entry(sec, "d", i);
        let amount = p(&e["amount"]);
        let total_assets = p(&e["totalAssets"]);
        let total_shares = p(&e["totalShares"]);
        let expected = p(&e["result"]);

        let state = CurveState {
            total_assets,
            total_shares,
        };
        let got = curve.preview_deposit(amount, state).unwrap();
        assert_eq!(
            got, expected,
            "linear deposit #{i}: amount={amount} state=({total_assets},{total_shares})"
        );
        checked += 1;
    }
    assert!(
        checked >= 30,
        "expected ≥30 linear deposit vectors, got {checked}"
    );
}

