#[test]
fn linear_convert_sweep() {
    let all = load_sweep();
    let sec = &all["linear_convert"];
    let n = count(sec);
    let curve = LinearCurve::new();
    let mut checked = 0;

    for i in 0..n {
        let raw_key_cs = format!("cs_{i}");
        let raw_key_ca = format!("ca_{i}");

        if let Some(obj) = sec.get(&raw_key_cs).and_then(|v| v.as_object()) {
            let assets = p(&obj["assets"]);
            let total_assets = p(&obj["totalAssets"]);
            let total_shares = p(&obj["totalShares"]);
            let expected = p(&obj["result"]);

            let state = CurveState {
                total_assets,
                total_shares,
            };
            let got = curve.convert_to_shares(assets, state).unwrap();
            assert_eq!(got, expected, "linear convertToShares #{i}");
            checked += 1;
        }

        if let Some(obj) = sec.get(&raw_key_ca).and_then(|v| v.as_object()) {
            let shares = p(&obj["shares"]);
            let total_shares = p(&obj["totalShares"]);
            let total_assets = p(&obj["totalAssets"]);
            let expected = p(&obj["result"]);

            let state = CurveState {
                total_assets,
                total_shares,
            };
            let got = curve.convert_to_assets(shares, state).unwrap();
            assert_eq!(got, expected, "linear convertToAssets #{i}");
            checked += 1;
        }
    }
    assert!(
        checked >= 50,
        "expected ≥50 linear convert vectors, got {checked}"
    );
}

