// =====================================================================
// Round-trip cross-method: deposit→redeem verified against Solidity
// =====================================================================

#[test]
fn round_trip_sweep() {
    let all = load_sweep();
    let sec = &all["round_trips"];
    let n = count(sec);
    let curve = prog_curve();
    let mut checked = 0;

    for i in 0..n {
        let e = entry(sec, "rt", i);
        let deposited = p(&e["deposited"]);
        let total_shares_before = p(&e["totalSharesBefore"]);
        let expected_shares = p(&e["sharesReceived"]);
        let expected_assets_back = p(&e["assetsReturned"]);
        let expected_loss = p(&e["loss"]);

        // Step 1: deposit
        let state_before = CurveState {
            total_assets: U256::ZERO,
            total_shares: total_shares_before,
        };
        let shares = curve.preview_deposit(deposited, state_before).unwrap();
        assert_eq!(
            shares, expected_shares,
            "round-trip #{i} deposit shares mismatch"
        );

        // Step 2: redeem
        let state_after = CurveState {
            total_assets: deposited,
            total_shares: total_shares_before + shares,
        };
        let assets_back = curve.preview_redeem(shares, state_after).unwrap();
        assert_eq!(
            assets_back, expected_assets_back,
            "round-trip #{i} redeem assets mismatch"
        );

        // Step 3: verify loss matches Solidity
        let loss = deposited - assets_back;
        assert_eq!(loss, expected_loss, "round-trip #{i} loss mismatch");

        // Protocol invariant: never profit from round-trip
        assert!(assets_back <= deposited, "round-trip #{i} profit detected");
        checked += 1;
    }
    assert!(
        checked >= 10,
        "expected ≥10 round-trip vectors, got {checked}"
    );
}
